final class TimestampReplayProtector {
    private final Duration allowedClockSkew;
    private final Duration replayWindow;
    private final ConcurrentMap<String, Long> seen = new ConcurrentHashMap<>();

    TimestampReplayProtector(Duration allowedClockSkew, Duration replayWindow) {
        this.allowedClockSkew = allowedClockSkew != null ? allowedClockSkew : Duration.ofMinutes(5);
        this.replayWindow = replayWindow != null ? replayWindow : Duration.ofMinutes(15);
    }

    void validateAndRemember(TimestampToken token) {
        if (token == null) throw new WebServiceException("Missing Timestamp token");
        if (token.created == null) throw new WebServiceException("Missing Timestamp Created");

        Instant now = Instant.now();

        Instant earliest = now.minus(replayWindow).minus(allowedClockSkew);
        Instant latest = now.plus(allowedClockSkew);

        if (token.created.isBefore(earliest) || token.created.isAfter(latest)) {
            throw new WebServiceException("Timestamp Created outside allowed window");
        }

        if (token.expires != null) {
            if (token.expires.isBefore(now.minus(allowedClockSkew))) {
                throw new WebServiceException("Timestamp has expired");
            }
            if (token.expires.isBefore(token.created)) {
                throw new WebServiceException("Timestamp Expires before Created");
            }
            if (Duration.between(token.created, token.expires).compareTo(replayWindow.plus(allowedClockSkew)) > 0) {
                throw new WebServiceException("Timestamp validity too long");
            }
        }

        cleanup(now);

        String key = buildReplayKey(token);
        long nowMs = now.toEpochMilli();
        Long prev = seen.putIfAbsent(key, nowMs);
        if (prev != null) {
            throw new WebServiceException("Replay detected");
        }
    }

    private String buildReplayKey(TimestampToken token) {
        if (token.id != null && !token.id.trim().isEmpty()) {
            return "id:" + token.id.trim();
        }
        String exp = token.expires != null ? token.expires.toString() : "";
        return "ts:" + token.created.toString() + "|" + exp;
    }

    private void cleanup(Instant now) {
        long cutoff = now.minus(replayWindow).minus(allowedClockSkew).toEpochMilli();
        for (Iterator<ConcurrentMap.Entry<String, Long>> it = seen.entrySet().iterator(); it.hasNext(); ) {
            ConcurrentMap.Entry<String, Long> e = it.next();
            Long t = e.getValue();
            if (t == null || t < cutoff) it.remove();
        }
    }
}

